<script lang="ts">
import {Options, Vue} from 'vue-class-component';

import JQuery from "jquery";
import store from "@/store";
import {closeAlertProgress, formatDateFromServer, isValidDate, navigateToFormStep, showAlert, showAlertError, showAlertProgress} from "@/functions";
import UserServices from "@/services/UserServices";

@Options({
  props: {
    data_item: Object,
    is_kyc: Boolean
  }
})
export default class ProfilePersonalData extends Vue {
  data_item
  is_kyc
  locale = store.getters.getLocale

  loading = false

  mounted(){
    if (this.data_item.country == null) this.data_item.country = ""
    this.data_item.date_birthday = formatDateFromServer(this.data_item.date_birthday, false)

    this.changeUserType()
    this.showHideMatrimonialRegime()
  }

  changeUserType(){
    if (this.data_item.user_type == 0){
      JQuery('#data_person').show()
      JQuery('#data_legal_person').hide()
      JQuery('#data_legal_person_title').hide()
      JQuery('#data_physical_person_title').show()
      //quitamos los required de empresa
      JQuery('#company_name').prop('required', false)
      JQuery('#company_activity').prop('required', false)
      JQuery('#nif').prop('required', false)
      JQuery('#legal_form').prop('required', false)
      JQuery('#company_address').prop('required', false)
      JQuery('#holders').prop('required', false)
      JQuery('#company_postal_code').prop('required', false)
      JQuery('#company_city').prop('required', false)
      JQuery('#company_province').prop('required', false)
      JQuery('#company_country').prop('required', false)
    } else if (this.data_item.user_type == 1){
      JQuery('#data_person').show()
      JQuery('#data_legal_person').show()
      JQuery('#data_legal_person_title').show()
      JQuery('#data_physical_person_title').hide()
      //ponemos los required de empresa
      JQuery('#company_name').prop('required', true)
      JQuery('#company_activity').prop('required', true)
      JQuery('#nif').prop('required', true)
      JQuery('#legal_form').prop('required', true)
      JQuery('#company_address').prop('required', true)
      JQuery('#holders').prop('required', true)
      JQuery('#company_postal_code').prop('required', true)
      JQuery('#company_city').prop('required', true)
      JQuery('#company_province').prop('required', true)
      JQuery('#company_country').prop('required', true)
    } else {
      JQuery('#data_person').hide()
    }
  }
  showHideMatrimonialRegime(){
    if (this.data_item.civil_status !== undefined && this.data_item.civil_status != 0){
      document.getElementById('div_economic_matrimonial_regime').style.display=''
      JQuery('#economic_matrimonial_regime').prop('required', true)
    } else {
      document.getElementById('div_economic_matrimonial_regime').style.display='none'
      JQuery('#economic_matrimonial_regime').prop('required', false)
    }
  }
  changeHolders() {
    if (isNaN(this.data_item.holders)){
      this.data_item.holders = 1
    }
    this.data_item.holders = Math.max(1, Math.min(this.data_item.holders, 3));
  }

  isValidDate(value){
    let date_in = JQuery('#' + value).val()
    if (date_in != undefined && date_in != "") {
      if (!isValidDate(date_in)) {
        showAlertError("El formato de la fecha no es correcto", this)
      }
    }
  }

  updateUserKYC(){
    if (this.data_item.kyc_valid == 1) {
      navigateToFormStep(2);
      return;
    }
    // eslint-disable-next-line @typescript-eslint/no-this-alias
    const self = this

    //si es soltero no hay regimen matrimonal
    if (this.data_item.civil_status == 0){
      this.data_item.economic_matrimonial_regime = null
    }

    // Name must have at least 2 characters with at least 1 vowel
    if (this.data_item.name.length < 2 || !/[aeiou]/i.test(this.data_item.name) || this.data_item.surname.length < 2 || !/[aeiou]/i.test(this.data_item.surname)) {
      showAlert("",this.$t('views.Nombre no válido'))
      return
    }

    if (this.data_item.phone.trim().length < 6) {
      showAlert("",this.$t('views.telefono corto'))
      return
    }

    this.loading = true
    showAlertProgress(this)
    UserServices.updateUser(this.data_item)
        .then(response => {
          showAlert("",this.$t('views.Se ha guardado correctamente'), false, function() {
            window.location.reload()
          })
          navigateToFormStep(2);
          self.loading = false
          closeAlertProgress(this)
        })
        .catch(function (error) {
          closeAlertProgress(self)
          showAlertError(error, self)
          self.loading = false
        });
  }

}
</script>
